110	    rows: Array<{ id: string; vector: number[]; chunk: Chunk; entry: WalkedFile["entry"] }>
111	  ) => Promise<string[]>;
112	  deleteChunksForFile?: (filePath: string) => Promise<void>;
113	  deleteAllChunks?: () => Promise<void>;
