116	interface RealPipeline {
117	  chunker: ChunkerModule;
118	  embedder: EmbedderModule;
119	  vectorStore: VectorStoreModule;
120	}
121	
122	async function loadRealPipeline(): Promise<RealPipeline> {
123	  const chunker = await tryImport<ChunkerModule>("./chunker.js");
124	  const embedder = await tryImport<EmbedderModule>("./embedder.js");
125	  const vectorStore = await tryImport<VectorStoreModule>("./vectorStore.js");
126	  const missing: string[] = [];
127	  if (!chunker) missing.push("scripts/llm/chunker.ts (P03)");
128	  if (!embedder) missing.push("scripts/llm/embedder.ts (P04)");
