130	  if (missing.length > 0) {
131	    throw new Error(
132	      `Cannot run real ingestion — missing pipeline modules:\n` +
133	        missing.map((m) => `  - ${m}`).join("\n") +
134	        `\nUse --dry-run, or implement the missing modules first.`
135	    );
136	  }
