138	    chunker: chunker!,
139	    embedder: embedder!,
140	    vectorStore: vectorStore!,
141	  };
142	}
143	
144	function isRateLimitError(err: unknown): boolean {
145	  if (!err || typeof err !== "object") return false;
146	  const e = err as { status?: number; code?: string; message?: string };
147	  if (e.status === 429) return true;
148	  if (e.code === "rate_limit") return true;
149	  if (typeof e.message === "string" && /rate.?limit|429/i.test(e.message)) return true;
150	  return false;
151	}
152	
153	async function withBackoff<T>(
154	  op: () => Promise<T>,
155	  label: string,
156	  maxAttempts = 5
157	): Promise<T> {
158	  let attempt = 0;
159	  let delay = 500;
160	  // eslint-disable-next-line no-constant-condition
161	  while (true) {
162	    try {
163	      return await op();
164	    } catch (err) {
165	      attempt++;
166	      if (attempt >= maxAttempts || !isRateLimitError(err)) throw err;
167	      const jitter = Math.random() * 250;
168	      const wait = delay + jitter;
169	      console.warn(
170	        `[ingest] ${label}: rate-limited, retry ${attempt}/${maxAttempts - 1} in ${Math.round(wait)}ms`
171	      );
172	      await new Promise((r) => setTimeout(r, wait));
173	      delay *= 2;
174	    }
175	  }
176	}
177	
178	async function embedAllChunks(
179	  embedder: EmbedderModule,
180	  chunks: Chunk[],
181	  label: string
182	): Promise<number[][]> {
183	  const out: number[][] = [];
184	  for (let i = 0; i < chunks.length; i += EMBED_BATCH_SIZE) {
185	    const slice = chunks.slice(i, i + EMBED_BATCH_SIZE);
186	    const vectors = await withBackoff(
187	      () => embedder.embedBatch(slice.map((c) => c.text)),
188	      `${label} embed batch ${i / EMBED_BATCH_SIZE + 1}`
189	    );
190	    if (vectors.length !== slice.length) {
191	      throw new Error(
192	        `embedder returned ${vectors.length} vectors for ${slice.length} chunks`
193	      );
194	    }
195	    out.push(...vectors);
196	  }
197	  return out;
198	}
