200	async function ingestOneReal(
201	  file: WalkedFile,
202	  state: IngestState,
203	  pipeline: RealPipeline,
204	  flags: CliFlags
205	): Promise<FileResult> {
206	  const prior = state.get(file.entry.path);
207	  const isUpdate = Boolean(prior);
208	  if (!flags.rebuild && state.isUnchanged(file.entry.path, file.contentHash)) {
209	    return { path: file.entry.path, status: "skipped", chunkCount: prior?.chunkIds.length ?? 0 };
210	  }
211	
212	  const chunks = await pipeline.chunker.chunkFile(file);
213	  if (chunks.length === 0) {
214	    if (prior && pipeline.vectorStore.deleteChunksForFile) {
215	      await pipeline.vectorStore.deleteChunksForFile(file.entry.path);
216	    }
217	    state.remove(file.entry.path);
218	    return { path: file.entry.path, status: isUpdate ? "updated" : "added", chunkCount: 0 };
219	  }
220	
221	  const vectors = await embedAllChunks(pipeline.embedder, chunks, file.entry.path);
222	
223	  if (prior && pipeline.vectorStore.deleteChunksForFile) {
224	    await pipeline.vectorStore.deleteChunksForFile(file.entry.path);
225	  }
226	
227	  const rows = chunks.map((chunk, i) => ({
228	    id: chunk.id ?? `${file.entry.path}#${chunk.index}`,
229	    vector: vectors[i],
230	    chunk,
231	    entry: file.entry,
232	  }));
233	  const chunkIds = await pipeline.vectorStore.upsertChunks(rows);
234	
235	  const rec: IngestRecord = {
236	    path: file.entry.path,
237	    contentHash: file.contentHash,
238	    chunkIds,
239	    ingestedAt: new Date().toISOString(),
240	  };
241	  state.record(rec);
242	
243	  return {
244	    path: file.entry.path,
245	    status: isUpdate ? "updated" : "added",
246	    chunkCount: chunkIds.length,
247	  };
248	}
249	
250	async function ingestOneDry(
251	  file: WalkedFile,
252	  state: IngestState,
253	  flags: CliFlags
254	): Promise<FileResult> {
255	  const prior = state.get(file.entry.path);
256	  if (flags.rebuild) {
257	    return {
258	      path: file.entry.path,
259	      status: prior ? "updated" : "added",
260	      chunkCount: prior?.chunkIds.length ?? 0,
261	    };
262	  }
263	  if (!prior) {
264	    return { path: file.entry.path, status: "added", chunkCount: 0 };
265	  }
266	  if (prior.contentHash === file.contentHash) {
267	    return { path: file.entry.path, status: "skipped", chunkCount: prior.chunkIds.length };
268	  }
269	  return { path: file.entry.path, status: "updated", chunkCount: prior.chunkIds.length };
270	}
271	
272	async function runWithConcurrency<T, R>(
273	  items: T[],
274	  limit: number,
275	  worker: (item: T) => Promise<R>
276	): Promise<R[]> {
277	  const results: R[] = new Array(items.length);
278	  let cursor = 0;
279	  const workers = Array.from({ length: Math.min(limit, items.length) }, async () => {
280	    while (true) {
281	      const i = cursor++;
282	      if (i >= items.length) return;
283	      results[i] = await worker(items[i]);
284	    }
285	  });
286	  await Promise.all(workers);
287	  return results;
288	}
289	
290	function formatLine(r: FileResult): string {
291	  const tag = r.status.padEnd(7);
292	  const count = `${r.chunkCount} chunk${r.chunkCount === 1 ? "" : "s"}`;
293	  const err = r.error ? `  (${r.error})` : "";
294	  return `  [${tag}] ${r.path} — ${count}${err}`;
295	}
296	
297	async function main(): Promise<number> {
298	  const flags = parseArgs(process.argv.slice(2));
299	  const corpusRoot = path.resolve(process.cwd(), "corpus");
300	  const onlyMatcher = flags.only ? globToRegExp(flags.only) : null;
301	
302	  const state = new IngestState(DEFAULT_STATE_PATH);
303	  await state.load();
304	
305	  console.log(
306	    `[ingest] mode=${flags.dryRun ? "dry-run" : "live"}` +
307	      `${flags.rebuild ? " rebuild" : ""}` +
308	      `${flags.only ? ` only=${flags.only}` : ""}`
309	  );
310	
311	  let pipeline: RealPipeline | null = null;
312	  if (!flags.dryRun) {
313	    pipeline = await loadRealPipeline();
314	    if (flags.rebuild) {
315	      if (pipeline.vectorStore.deleteAllChunks) {
316	        await pipeline.vectorStore.deleteAllChunks();
317	      }
318	      state.clearAll();
319	    }
320	  }
321	
322	  const files: WalkedFile[] = [];
323	  for await (const f of walk({
324	    corpusRoot,
325	    only: onlyMatcher ? (p) => onlyMatcher.test(p) : undefined,
326	  })) {
327	    files.push(f);
328	  }
329	
330	  if (files.length === 0) {
331	    console.log("[ingest] no eligible files in manifest");
332	    return 0;
333	  }
334	
335	  const results = await runWithConcurrency(files, CONCURRENCY, async (file) => {
336	    try {
337	      const result = flags.dryRun
338	        ? await ingestOneDry(file, state, flags)
339	        : await ingestOneReal(file, state, pipeline!, flags);
340	      console.log(formatLine(result));
341	      return result;
342	    } catch (err) {
343	      const message = err instanceof Error ? err.message : String(err);
344	      const result: FileResult = {
345	        path: file.entry.path,
346	        status: "failed",
347	        chunkCount: 0,
348	        error: message,
349	      };
350	      console.log(formatLine(result));
351	      return result;
352	    }
353	  });
354	
355	  if (!flags.dryRun) {
356	    await state.save();
357	  }
358	
359	  const counts = { added: 0, updated: 0, skipped: 0, failed: 0 };
360	  for (const r of results) counts[r.status]++;
361	
362	  console.log(
363	    `[ingest] summary: added=${counts.added} updated=${counts.updated} ` +
364	      `skipped=${counts.skipped} failed=${counts.failed} ` +
365	      `(total=${results.length})`
366	  );
367	
368	  if (counts.failed > 0) {
369	    console.error(`[ingest] ${counts.failed} file(s) failed`);
370	    return 1;
371	  }
372	  return 0;
373	}
374	
375	main()
376	  .then((code) => process.exit(code))
377	  .catch((err) => {
378	    console.error(err);
379	    process.exit(1);
380	  });
